async (params, browser) => {
  // Search Udemy
  await browser.open(`https://www.udemy.com/courses/search/?q=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('[class*=\'course-card\'], [data-purpose=\'course-card-container\'], [class*=\'CourseCard\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract course results
  const search_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('[class*="course-card"], [data-purpose="course-card-container"], [class*="CourseCard"]'); for (let i = 0; i < Math.min(items.length, 15); i++) { const el = items[i]; const titleEl = el.querySelector('h3, [data-purpose="course-title-url"] div, [class*="title"]'); const instructorEl = el.querySelector('[data-purpose="safely-set-inner-html:course-card:visible-instructors"], [class*="instructor"], [class*="teacher"]'); const ratingEl = el.querySelector('[class*="rating"] span, [data-purpose="rating-number"]'); const studentsEl = el.querySelector('[class*="enrollment"], [class*="students"]'); const priceEl = el.querySelector('[data-purpose="course-price-text"] span, [class*="price"] span, [class*="price-text"]'); const linkEl = el.querySelector('a[href*="/course/"]'); const imgEl = el.querySelector('img[src*="img-c"], img[src*="udemy"], img'); const levelEl = el.querySelector('[class*="level"], [class*="difficulty"]'); const durationEl = el.querySelector('[class*="duration"], [class*="content-length"]'); const bestsellerEl = el.querySelector('[class*="bestseller"], [data-purpose="badge"]'); results.push({ name: titleEl ? titleEl.textContent.trim() : '', instructor: instructorEl ? instructorEl.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', students: studentsEl ? studentsEl.textContent.trim() : '', price: priceEl ? priceEl.textContent.trim() : '', level: levelEl ? levelEl.textContent.trim() : '', duration: durationEl ? durationEl.textContent.trim() : '', is_bestseller: !!bestsellerEl, image: imgEl ? imgEl.getAttribute('src') : '', url: linkEl ? linkEl.href : '' }); } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
